<?php
/**
 * Plugin Name: PowerUp Review Seed 20260604 Excel
 * Description: Imports rewritten 5-star Amazon Excel reviews into WooCommerce locally and on deployment.
 * Version: 2026.06.04.5
 */

defined( 'ABSPATH' ) || exit;

add_action( 'init', 'powerup_review_seed_20260604_excel_run', 96 );

function powerup_review_seed_20260604_excel_run() {
	if ( ! function_exists( 'wc_get_product_id_by_sku' ) ) {
		return;
	}

	$version = '2026.06.04.5';
	if ( get_option( 'powerup_review_seed_20260604_excel_version' ) === $version ) {
		return;
	}

	powerup_review_seed_20260604_excel_remove_replaced_reviews();
	$inserted = array();

	foreach ( powerup_review_seed_20260604_excel_data() as $review ) {
		$product_id = wc_get_product_id_by_sku( (string) $review['asin'] );
		if ( ! $product_id ) {
			continue;
		}

		$comment_id = powerup_review_seed_20260604_excel_upsert( (int) $product_id, $review );
		if ( $comment_id ) {
			$inserted[] = $comment_id;
		}
	}

	powerup_review_seed_20260604_excel_sync_stats();

	if ( function_exists( 'wp_cache_flush' ) ) {
		wp_cache_flush();
	}

	update_option( 'powerup_review_seed_20260604_excel_version', $version, false );
	update_option( 'powerup_review_seed_20260604_excel_last_result', array( 'version' => $version, 'inserted' => count( $inserted ), 'run_time' => current_time( 'mysql' ) ), false );
}

function powerup_review_seed_20260604_excel_remove_replaced_reviews() {
	global $wpdb;
	$asins = array( 'B0FFGSPWWS', 'B0FCLY4DC1', 'B0FCM6HXVX', 'B0FQNYCRH2' );

	foreach ( $asins as $asin ) {
		$product_id = wc_get_product_id_by_sku( $asin );
		if ( ! $product_id ) {
			continue;
		}

		$comment_ids = $wpdb->get_col(
			$wpdb->prepare(
				"SELECT c.comment_ID
				 FROM {$wpdb->comments} c
				 INNER JOIN {$wpdb->commentmeta} m_asin ON c.comment_ID = m_asin.comment_id
				 INNER JOIN {$wpdb->commentmeta} m_source ON c.comment_ID = m_source.comment_id
				 WHERE c.comment_post_ID = %d
				 AND c.comment_type = %s
				 AND m_asin.meta_key = %s
				 AND m_asin.meta_value = %s
				 AND m_source.meta_key = %s
				 AND m_source.meta_value NOT LIKE %s",
				$product_id, 'review', '_powerup_review_source_asin', $asin, '_powerup_review_source_id', 'excel-20260604-%'
			)
		);

		foreach ( $comment_ids as $comment_id ) {
			wp_delete_comment( (int) $comment_id, true );
		}
	}
}

function powerup_review_seed_20260604_excel_upsert( $product_id, array $review ) {
	global $wpdb;

	$source_id = sanitize_key( (string) $review['source_id'] );
	$existing  = (int) $wpdb->get_var( $wpdb->prepare( "SELECT comment_id FROM {$wpdb->commentmeta} WHERE meta_key = %s AND meta_value = %s LIMIT 1", '_powerup_review_source_id', $source_id ) );

	$comment_data = array(
		'comment_post_ID'      => $product_id,
		'comment_author'       => sanitize_text_field( (string) $review['author'] ),
		'comment_author_email' => sanitize_email( (string) $review['email'] ),
		'comment_author_url'   => '',
		'comment_content'      => wp_kses_post( (string) $review['content'] ),
		'comment_type'         => 'review',
		'comment_parent'       => 0,
		'user_id'              => 0,
		'comment_approved'     => 1,
		'comment_date'         => (string) $review['date'],
		'comment_date_gmt'     => get_gmt_from_date( (string) $review['date'] ),
	);

	if ( $existing ) {
		$comment_data['comment_ID'] = $existing;
		wp_update_comment( $comment_data );
		$comment_id = $existing;
	} else {
		$comment_id = wp_insert_comment( $comment_data );
	}

	if ( ! $comment_id || is_wp_error( $comment_id ) ) {
		return 0;
	}

	update_comment_meta( $comment_id, 'rating', 5 );
	update_comment_meta( $comment_id, '_powerup_review_source_id', $source_id );
	update_comment_meta( $comment_id, '_powerup_review_source', 'Amazon Excel review rewritten for independent store' );
	update_comment_meta( $comment_id, '_powerup_review_source_asin', sanitize_text_field( (string) $review['asin'] ) );
	update_comment_meta( $comment_id, '_powerup_review_source_row', (int) $review['source_row'] );

	if ( ! empty( $review['title'] ) ) {
		update_comment_meta( $comment_id, 'powerup_review_title', sanitize_text_field( (string) $review['title'] ) );
	}

	return (int) $comment_id;
}

function powerup_review_seed_20260604_excel_sync_stats() {
	if ( ! class_exists( 'WC_Comments' ) || ! function_exists( 'wc_get_product_id_by_sku' ) ) {
		return;
	}

	$asins = array( 'B0FFGSPWWS', 'B0FCLY4DC1', 'B0FCM6HXVX', 'B0FQNYCRH2', 'B0GGTDWRNN', 'B0GGTKHN4G' );
	foreach ( $asins as $asin ) {
		$product_id = wc_get_product_id_by_sku( $asin );
		$product    = $product_id ? wc_get_product( $product_id ) : false;
		if ( ! $product instanceof WC_Product ) {
			continue;
		}
		$product->set_rating_counts( WC_Comments::get_rating_counts_for_product( $product ) );
		$product->set_average_rating( WC_Comments::get_average_rating_for_product( $product ) );
		$product->set_review_count( WC_Comments::get_review_count_for_product( $product ) );
		$product->save();
		if ( function_exists( 'wc_delete_product_transients' ) ) {
			wc_delete_product_transients( $product_id );
		}
	}
}

